import {
  createContext,
  useContext,
  useEffect,
  useMemo,
  useState,
  type PropsWithChildren,
} from "react";
import {
  getOrderlyEnvConfig,
  type OrderlyEnvConfig,
} from "@/utils/environment";
import {
  buildStoredAdminAuthHeaders,
  hasCompleteStoredAdminApiKey,
  readStoredAdminApiKey,
  type MessageFactor,
} from "@/utils/adminKeyAuth";
import { clearConnectionStorage } from "@/utils/session";
import { BrokerInfoProvider } from "./BrokerInfoProvider";

type ConfigStoreLike = {
  get: <T = unknown>(key: keyof OrderlyEnvConfig | string) => T;
};

type KeyStoreLike = {
  address: string;
  getAccountId: () => string | null | undefined;
  clear: () => void;
};

export type AppContextState = {
  logged: boolean;
  login: () => void;
  logout: () => void;
  account: {
    signer: {
      sign: (payload: MessageFactor) => Promise<Record<string, string>>;
    };
  };
  configStore: ConfigStoreLike;
  keyStore: KeyStoreLike;
  isValidating: boolean;
  getAccountId: () => string | null | undefined;
};

export const AppContext = createContext<AppContextState | null>(null);

function removeStoredAuth() {
  if (typeof window === "undefined") return;
  clearConnectionStorage();
}

function buildFallbackState(): AppContextState {
  const envConfig = getOrderlyEnvConfig();
  const configStore: ConfigStoreLike = {
    get: key => envConfig[key as keyof OrderlyEnvConfig] as never,
  };
  const getAccountId = () => readStoredAdminApiKey()?.accountId;
  const keyStore: KeyStoreLike = {
    address: "admin",
    getAccountId,
    clear: removeStoredAuth,
  };

  return {
    logged: hasCompleteStoredAdminApiKey(),
    login: () => {},
    logout: removeStoredAuth,
    account: {
      signer: {
        sign: async payload => buildStoredAdminAuthHeaders(payload),
      },
    },
    configStore,
    keyStore,
    isValidating: false,
    getAccountId,
  };
}

export function AppProvider({ children }: PropsWithChildren) {
  const [version, setVersion] = useState(0);

  useEffect(() => {
    const refresh = () => setVersion(value => value + 1);
    window.addEventListener("authChanged", refresh);
    window.addEventListener("storage", refresh);
    return () => {
      window.removeEventListener("authChanged", refresh);
      window.removeEventListener("storage", refresh);
    };
  }, []);

  const value = useMemo(() => buildFallbackState(), [version]);
  return (
    <AppContext.Provider value={value}>
      <BrokerInfoProvider accountId={value.getAccountId() || undefined}>
        {children}
      </BrokerInfoProvider>
    </AppContext.Provider>
  );
}

export function useAppContext() {
  const provided = useContext(AppContext);
  const [version, setVersion] = useState(0);

  useEffect(() => {
    const refresh = () => setVersion(value => value + 1);
    window.addEventListener("authChanged", refresh);
    window.addEventListener("storage", refresh);
    return () => {
      window.removeEventListener("authChanged", refresh);
      window.removeEventListener("storage", refresh);
    };
  }, []);

  return useMemo(() => provided ?? buildFallbackState(), [provided, version]);
}
